package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileInputStream;
import java.io.InputStreamReader;
import java.io.Reader;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private File file;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() {
        file = mock(File.class);
        charset = Charset.defaultCharset();
        format = mock(CSVFormat.class);
    }

    @Test
    void testParse_file_success() throws Exception {
        // Since Mockito 3 does not support mockConstruction, avoid mocking FileInputStream/InputStreamReader construction.
        // Instead, spy or mock the CSVParser constructor or use a real file with a temporary file if needed.
        // Here we just test parse with a mocked file and format, assuming no real IO.

        // We create a stub CSVParser to return when constructor is called via spy or partial mock
        // But since CSVParser.parse(File, Charset, CSVFormat) is static and creates new CSVParser internally,
        // we cannot mock constructor easily with Mockito 3.
        // So test just the method call with a real file (mock returns a path to an existing file)
        // Instead, create a temporary file with minimal content:

        java.nio.file.Path tempFile = java.nio.file.Files.createTempFile("test", ".csv");
        java.nio.file.Files.write(tempFile, "header1,header2\nvalue1,value2\n".getBytes(charset));

        File realFile = tempFile.toFile();

        CSVFormat realFormat = CSVFormat.DEFAULT.withHeader();

        CSVParser parser = CSVParser.parse(realFile, charset, realFormat);
        assertNotNull(parser);
        // headerMap depends on format initialization
        assertNotNull(parser.getHeaderMap());

        parser.close();

        java.nio.file.Files.deleteIfExists(tempFile);
    }

    @Test
    void testParse_file_nullFile() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((File)null, charset, format));
        assertEquals("file", ex.getMessage());
    }

    @Test
    void testParse_file_nullFormat() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(file, charset, null));
        assertEquals("format", ex.getMessage());
    }

    @Test
    void testParse_file_nullCharset() {
        // Charset can be null? The method does not check null for charset explicitly, so it may NPE internally
        assertThrows(NullPointerException.class, () -> CSVParser.parse(file, null, format));
    }
}
